/**
 * Calculates annotations' vertical visible area in the ChartGrid.
 *
 * @param numTracks - The number of tracks you want to consider for the annotations vertical area
 * @param visibleTracksAmountLimit - The limit amount of visible tracks. When `undefined`, equals to the total number of tracks.
 * @param numHiddenTracks - The number of hidden tracks. The default equals to 0. Depending on the amount of hidden tracks, the visible area will be reduced to compensate the area the should not be displayed.
 * @returns The annotations' visible vertical area in pixels in the ChartGrid.
 */
export declare const getAnnotationsVisibleArea: (numTracks: number, visibleTracksAmountLimit?: number, numHiddenTracks?: number) => number;
